import{c as a,Q as n,j as r,m as t}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"What Is Harness Engineering? (Alternative Sources)","description":"","frontmatter":{"url":"https://harness-engineering.ai/blog/what-is-harness-engineering/","title":"What Is Harness Engineering? (Alternative Sources)","status":"ALTERNATIVE_SOURCE_RETRIEVED","alternative_urls":["https://atlan.com/know/what-is-harness-engineering/","https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d"],"date_updated":"2026-05-18T00:00:00.000Z","original_status":"URL_NOT_FOUND"},"headers":[],"relativePath":"research/ai-articles/31-harness-engineering-what-is.md","filePath":"research/ai-articles/31-harness-engineering-what-is.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/31-harness-engineering-what-is.md"};function i(o,e,l,h,g,d){return n(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="harness-engineering-什麼是-harness-engineering" tabindex="-1">Harness Engineering：什麼是 Harness Engineering？ <a class="header-anchor" href="#harness-engineering-什麼是-harness-engineering" aria-label="Permalink to &quot;Harness Engineering：什麼是 Harness Engineering？&quot;">​</a></h1><h2 id="原始-url-說明" tabindex="-1">原始 URL 說明 <a class="header-anchor" href="#原始-url-說明" aria-label="Permalink to &quot;原始 URL 說明&quot;">​</a></h2><p>原始 URL (<code>harness-engineering.ai</code>) 返回 HTTP 503，可能為幻覺 URL。本文內容整合自以下可訪問的替代來源：</p><ul><li><strong>Atlan</strong>：<a href="https://atlan.com/know/what-is-harness-engineering/" target="_blank" rel="noreferrer">https://atlan.com/know/what-is-harness-engineering/</a></li><li><strong>Medium (Adnan Masood)</strong>：<a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a></li></ul><hr><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><h3 id="harness-engineering-定義" tabindex="-1">Harness Engineering 定義 <a class="header-anchor" href="#harness-engineering-定義" aria-label="Permalink to &quot;Harness Engineering 定義&quot;">​</a></h3><p>Harness Engineering 是設計與維護控制系統的紀律，用以管控 AI Agent 行為。按 Mitchell Hashimoto 2026 年的公式：<strong>Agent = Model + Harness</strong>。Harness 涵蓋除了模型以外的所有內容——指導 Agent、驗證輸出的感測器，以及資料上下文 pipeline。</p><h3 id="架構核心-model-harness" tabindex="-1">架構核心：Model + Harness <a class="header-anchor" href="#架構核心-model-harness" aria-label="Permalink to &quot;架構核心：Model + Harness&quot;">​</a></h3><p>傳統 AI 系統著重模型本身；Harness Engineering 的轉向在於認知 <strong>Harness 才是生產價值的決定因素</strong>。業界數據揭露：</p><ul><li><strong>88% 的 AI Agent 專案未能進入生產環境</strong>，瓶頸不在模型能力，而在「缺乏生產級 Harness」</li><li><strong>65% 的企業 AI 專案失敗根源於 Harness 層級的資料缺陷</strong>，而非推理限制</li><li><strong>27% 的 AI Agent 專案失敗由資料品質問題引起</strong>，使資料層治理成為最被忽視的失敗點</li></ul><h3 id="control-agency-runtime-架構" tabindex="-1">Control / Agency / Runtime 架構 <a class="header-anchor" href="#control-agency-runtime-架構" aria-label="Permalink to &quot;Control / Agency / Runtime 架構&quot;">​</a></h3><p>Harness 由三個層面組成：</p><h4 id="guides-前饋控制" tabindex="-1">Guides（前饋控制） <a class="header-anchor" href="#guides-前饋控制" aria-label="Permalink to &quot;Guides（前饋控制）&quot;">​</a></h4><ul><li><strong>System Prompts</strong>：定義 Agent 的角色與任務範圍</li><li><strong>AGENTS.md / 規格檔</strong>：明確允許的行為與慣例</li><li><strong>Constraint Documents</strong>：建立邊界與禁區</li><li><strong>Context Pipelines</strong>：提供經認證、有溯源的資料</li></ul><h4 id="sensors-反饋控制" tabindex="-1">Sensors（反饋控制） <a class="header-anchor" href="#sensors-反饋控制" aria-label="Permalink to &quot;Sensors（反饋控制）&quot;">​</a></h4><ul><li><strong>Evaluation Suites</strong>：依據基礎事實評分輸出</li><li><strong>Validation Loops</strong>：在部署前攔截約束違反</li><li><strong>Output Parsers</strong>：將文字轉換為可驗證的型別資料</li><li><strong>Drift Detectors</strong>：監測非預期的行為變化</li></ul><h4 id="runtime-與-determinism" tabindex="-1">Runtime 與 Determinism <a class="header-anchor" href="#runtime-與-determinism" aria-label="Permalink to &quot;Runtime 與 Determinism&quot;">​</a></h4><p><strong>關鍵洞察</strong>：Harness 的目標是將「概率性推理」轉換為「可靠、確定性的行動」。企業失敗主要源於基礎設施缺陷，而非推理限制。</p><h3 id="生產影響-數據治理的倍數效應" tabindex="-1">生產影響：數據治理的倍數效應 <a class="header-anchor" href="#生產影響-數據治理的倍數效應" aria-label="Permalink to &quot;生產影響：數據治理的倍數效應&quot;">​</a></h3><p>採用受治理資料上下文的 Harness 團隊報告了 38% 的 SQL 精準度改善（使用相同模型與架構）。競爭優勢不在推理引擎，而在供給它的控制系統。</p><p>經濟乘數效應同樣顯著：</p><ul><li><strong>成本削減</strong>：從 $3/百萬 tokens 降至 $0.30/百萬 tokens（10 倍改善）</li><li><strong>延遲優化</strong>：4 倍延遲改善，透過 prefix 穩定性與語義路由技術</li></ul><h3 id="界定邊界-bounded-workflows-優於-autonomous-swarms" tabindex="-1">界定邊界：Bounded Workflows 優於 Autonomous Swarms <a class="header-anchor" href="#界定邊界-bounded-workflows-優於-autonomous-swarms" aria-label="Permalink to &quot;界定邊界：Bounded Workflows 優於 Autonomous Swarms&quot;">​</a></h3><p>生產部隊壓倒性偏好：</p><ul><li><strong>確定性、單一 Agent 系統</strong>，具明確人類檢查點 ✅</li><li><strong>優於自主多 Agent 群體</strong>，後者被證實「易脆弱、成本禁高、幾乎無法除錯」❌</li></ul><h3 id="標準化趨勢-mcp-與-a2a-協議" tabindex="-1">標準化趨勢：MCP 與 A2A 協議 <a class="header-anchor" href="#標準化趨勢-mcp-與-a2a-協議" aria-label="Permalink to &quot;標準化趨勢：MCP 與 A2A 協議&quot;">​</a></h3><p>兩個關鍵協議正整合生態：</p><ul><li><strong>Model Context Protocol (MCP)</strong>：標準化 Agent-to-Tool 互動</li><li><strong>Agent-to-Agent Protocol (A2A)</strong>：跨框架委派能力</li></ul><hr><h2 id="關鍵引用" tabindex="-1">關鍵引用 <a class="header-anchor" href="#關鍵引用" aria-label="Permalink to &quot;關鍵引用&quot;">​</a></h2><h3 id="引用-1-atlan" tabindex="-1">引用 1（Atlan） <a class="header-anchor" href="#引用-1-atlan" aria-label="Permalink to &quot;引用 1（Atlan）&quot;">​</a></h3><blockquote><p>&quot;Harness engineering is the discipline of designing and maintaining control systems that govern AI agent behavior. Per Mitchell Hashimoto&#39;s 2026 formula: <strong>Agent = Model + Harness</strong>. The harness encompasses everything except the model itself—guides that direct agents, sensors that validate outputs, and data context pipelines.&quot;</p></blockquote><p><strong>出處</strong>：<a href="https://atlan.com/know/what-is-harness-engineering/" target="_blank" rel="noreferrer">https://atlan.com/know/what-is-harness-engineering/</a></p><h3 id="引用-2-atlan-產業背景" tabindex="-1">引用 2（Atlan - 產業背景） <a class="header-anchor" href="#引用-2-atlan-產業背景" aria-label="Permalink to &quot;引用 2（Atlan - 產業背景）&quot;">​</a></h3><blockquote><p>&quot;The industry context is stark: &#39;88% of AI agent projects never reach production.&#39; The bottleneck isn&#39;t model capability—it&#39;s the absence of production-grade harnesses.&quot;</p></blockquote><p><strong>出處</strong>：<a href="https://atlan.com/know/what-is-harness-engineering/" target="_blank" rel="noreferrer">https://atlan.com/know/what-is-harness-engineering/</a></p><h3 id="引用-3-medium-架構層級" tabindex="-1">引用 3（Medium - 架構層級） <a class="header-anchor" href="#引用-3-medium-架構層級" aria-label="Permalink to &quot;引用 3（Medium - 架構層級）&quot;">​</a></h3><blockquote><p>&quot;The harness is the singular architectural layer responsible for translating probabilistic reasoning into dependable, deterministic action.&quot;</p></blockquote><p><strong>出處</strong>：<a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a></p><h3 id="引用-4-medium-企業失敗率" tabindex="-1">引用 4（Medium - 企業失敗率） <a class="header-anchor" href="#引用-4-medium-企業失敗率" aria-label="Permalink to &quot;引用 4（Medium - 企業失敗率）&quot;">​</a></h3><blockquote><p>&quot;Enterprise failures stem primarily from infrastructure defects rather than reasoning limitations. The research indicates &#39;65% of enterprise AI project failures trace back to harness-level data defects.&#39;&quot;</p></blockquote><p><strong>出處</strong>：<a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a></p><hr><h2 id="與-karpathy-mnilax-規則的關聯" tabindex="-1">與 Karpathy/Mnilax 規則的關聯 <a class="header-anchor" href="#與-karpathy-mnilax-規則的關聯" aria-label="Permalink to &quot;與 Karpathy/Mnilax 規則的關聯&quot;">​</a></h2><h3 id="rule-4-goal-driven-目標導向-對應" tabindex="-1">Rule 4 - Goal-Driven（目標導向）對應 <a class="header-anchor" href="#rule-4-goal-driven-目標導向-對應" aria-label="Permalink to &quot;Rule 4 - Goal-Driven（目標導向）對應&quot;">​</a></h3><p>Harness Engineering 的 <strong>Sensors &amp; Validation Loops</strong> 直接實現 Rule 4 的核心原則：</p><ul><li><strong>完成條件必須機械性可驗證</strong>：Evaluation Suites 與 Drift Detectors 提供客觀量化指標，而非口頭「看起來正確」</li><li><strong>Checkpoint 驗證</strong>：每個重要步驟的輸出解析為型別資料，自動驗證，與「展示前 5 行 / 後 5 行輸出」的精神一致</li></ul><h3 id="rule-12-fail-loud-顯著失敗-對應" tabindex="-1">Rule 12 - Fail Loud（顯著失敗）對應 <a class="header-anchor" href="#rule-12-fail-loud-顯著失敗-對應" aria-label="Permalink to &quot;Rule 12 - Fail Loud（顯著失敗）對應&quot;">​</a></h3><p>Harness 的 <strong>Constraint Documents 與 Output Parsers</strong> 實現 Rule 12：</p><ul><li>違反邊界時立即拋出異常，不靜默跳過</li><li>Output parsers 強制驗證，無法通過無型別的 JSON；失敗時完整回報錯誤堆疊</li></ul><h3 id="長期記憶-harness-design" tabindex="-1">長期記憶 + Harness Design <a class="header-anchor" href="#長期記憶-harness-design" aria-label="Permalink to &quot;長期記憶 + Harness Design&quot;">​</a></h3><p>CLAUDE.md 的 <strong>Auto Memory + MEMORY.md 雙層</strong> 對應 Harness 的 <strong>Context Pipelines</strong>：</p><ul><li>認證資料源（Git 追蹤的 MEMORY.md）</li><li>溯源歷史（session 日期、決策時間戳）</li><li>Drift 偵測（違反慣例的警告）</li></ul><hr><h2 id="實踐啟示" tabindex="-1">實踐啟示 <a class="header-anchor" href="#實踐啟示" aria-label="Permalink to &quot;實踐啟示&quot;">​</a></h2><h3 id="對-claude-code-設計的意涵" tabindex="-1">對 Claude Code 設計的意涵 <a class="header-anchor" href="#對-claude-code-設計的意涵" aria-label="Permalink to &quot;對 Claude Code 設計的意涵&quot;">​</a></h3><ol><li><strong>Constraint-First</strong>：定義 Harness（AGENTS.md、core.md 規則）優於寬泛模型提示</li><li><strong>Sensors 即文件</strong>：<code>.claude/rules/</code>、<code>memory/MEMORY.md</code> 兼具「指南」與「驗證樞紐」雙重功能</li><li><strong>Data Governance</strong>：MEMORY.md 的控制（字元硬限制、Git 追蹤）確保資料品質與溯源</li><li><strong>Deterministic Gateway</strong>：Git 工作流程（stage → commit → push）是「概率性文字」轉「確定性行動」的最小 Harness</li></ol>',58)])])}const m=a(s,[["render",i]]);export{c as __pageData,m as default};
